#include <bits/stdc++.h>
using namespace std;
int n,q,m,a[302],ans,mark[302],f[302],deep[302];
vector<int> s[302];
void set_deep(){
    deep[0]=0;
    queue<int> b;
    b.push(0);
    while(!b.empty()){
    	int u=b.front();
    	b.pop();
    	for(int i=0;i<s[u].size();i++){
    		deep[s[u][i]]=deep[u]+1;
    		b.push(s[u][i]);
		}
		//cout<<"1\n";
	}
}
void find_ans(){
	memset(mark,0,sizeof(mark));
	for(int i=1;i<=m;i++){
		int j=a[i];
		while(1){
			if(mark[j]==1){
				if(deep[j]<deep[ans])ans=j;
				break;//有1则祖先全被遍历 
			}
			mark[j]=1;
			if(j==f[j])break;
			j=f[j];
		}
		//if(mark[j]==1 && deep[j]<deep[ans])ans=j;
	}
	int tmp=ans;
	while(1){
		tmp=f[tmp];
		if(tmp>ans)ans=tmp;
		if(tmp==0)break;
	}
}
int main(){
    cin>>n;
    for(int i=1;i<n;i++){
        cin>>f[i];
        if(f[i]!=i)s[f[i]].push_back(i);
    }
    //cout<<"OK"<<endl;
	set_deep();
    cin>>q;
    while(q--){
        cin>>m;
        //cout<<m<<endl;
        for(int i=1;i<=m;i++)cin>>a[i];
        ans=a[1];
        //cout<<"good\n";
        find_ans();
        cout<<ans<<endl;
    }
    return 0;
}
